package dev.harrison.rendacomcarro.attachment.domain;
import jakarta.persistence.*;import java.time.LocalDateTime;import java.util.UUID;
@Entity@Table(name="attachment")public class Attachment {@Id private UUID id;@Enumerated(EnumType.STRING)@Column(name="owner_type",nullable=false)private OwnerType ownerType;@Column(name="owner_id",nullable=false)private UUID ownerId;@Column(name="original_filename",nullable=false)private String originalFilename;@Column(name="stored_path",nullable=false,unique=true)private String storedPath;@Column(name="content_type",nullable=false)private String contentType;@Column(name="size_bytes",nullable=false)private long sizeBytes;@Column(name="checksum_sha256",nullable=false)private String checksumSha256;@Column(nullable=false)private String status;@Column(name="created_at",nullable=false)private LocalDateTime createdAt;protected Attachment(){}public static Attachment create(OwnerType ownerType,UUID ownerId,String original,String stored,String contentType,long size,String checksum){if(ownerType==null||ownerId==null)throw new IllegalArgumentException("Proprietário do anexo é obrigatório");Attachment a=new Attachment();a.id=UUID.randomUUID();a.ownerType=ownerType;a.ownerId=ownerId;a.originalFilename=original;a.storedPath=stored;a.contentType=contentType;a.sizeBytes=size;a.checksumSha256=checksum;a.status="ACTIVE";a.createdAt=LocalDateTime.now();return a;}public void archive(){status="ARCHIVED";}public UUID getId(){return id;}public String getOriginalFilename(){return originalFilename;}public String getStoredPath(){return storedPath;}public String getContentType(){return contentType;}public long getSizeBytes(){return sizeBytes;}public String getChecksumSha256(){return checksumSha256;}public String getStatus(){return status;}}
